WHERE u.status = 1 AND ct.status = 1


        AND c.status = #{query.status}


        AND c.status = 1



    AND c.content_id = #{query.contentId}


    AND c.user_id = #{query.userId}


    AND c.content LIKE CONCAT('%', #{query.content}, '%')


    AND c.comment_type = #{query.commentType}


    AND c.paragraph_id = #{query.paragraphId}


    AND c.created_time >= #{query.startTime}


    AND c.created_time <= #{query.endTime}

